// src/components/Common/productCard.js
import React, { useState } from "react";

export default function ProductCard({ 
  product, 
  category, 
  isEditable = false, 
  onEdit, 
  onDelete,
  showActions = true,
  onClick 
}) {
  const [isHovered, setIsHovered] = useState(false);

  return (
    <div 
      className="product-card"
      onClick={() => onClick && onClick(product)}
      onMouseEnter={() => setIsHovered(true)}
      onMouseLeave={() => setIsHovered(false)}
      style={{
        background: 'rgba(255,255,255,0.1)',
        backdropFilter: 'blur(15px)',
        borderRadius: '25px',
        overflow: 'hidden',
        cursor: onClick ? 'pointer' : 'default',
        transition: 'all 0.3s ease',
        border: '1px solid rgba(34,197,94,0.2)',
        animation: 'fadeIn 0.5s ease-out',
        position: 'relative'
      }}
      onMouseEnterStyle={(e) => {
        e.currentTarget.style.transform = 'translateY(-8px)';
        e.currentTarget.style.boxShadow = '0 15px 35px rgba(0,0,0,0.3)';
        e.currentTarget.style.borderColor = 'rgba(34,197,94,0.5)';
      }}
      onMouseLeaveStyle={(e) => {
        e.currentTarget.style.transform = 'translateY(0)';
        e.currentTarget.style.boxShadow = 'none';
        e.currentTarget.style.borderColor = 'rgba(34,197,94,0.2)';
      }}
    >
      {/* صورة المنتج */}
      <div style={{ position: 'relative' }}>
        <img 
          src={product.image || "https://cdn-icons-png.flaticon.com/512/1046/1046784.png"} 
          alt={product.name} 
          style={{
            width: '100%',
            height: '200px',
            objectFit: 'cover',
            transition: 'transform 0.3s ease'
          }}
          onMouseEnter={(e) => { e.currentTarget.style.transform = 'scale(1.05)' }}
          onMouseLeave={(e) => { e.currentTarget.style.transform = 'scale(1)' }}
        />
        {category && (
          <span style={{
            position: 'absolute',
            top: '10px',
            right: '10px',
            padding: '4px 12px',
            borderRadius: '20px',
            fontSize: '0.7rem',
            fontWeight: 'bold',
            color: 'white',
            background: category.color || '#22c55e',
            boxShadow: '0 2px 5px rgba(0,0,0,0.2)'
          }}>
            {category.icon} {category.name}
          </span>
        )}
      </div>
      
      {/* أيقونة المنتج (مثل logo في restaurantCard) */}
      <div style={{
        width: '60px',
        height: '60px',
        borderRadius: '50%',
        marginTop: '-30px',
        marginLeft: '20px',
        border: '3px solid #22c55e',
        background: '#1a1a3a',
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        fontSize: '1.8rem',
        boxShadow: '0 5px 15px rgba(0,0,0,0.2)'
      }}>
        {category?.icon || '🍽️'}
      </div>
      
      {/* معلومات المنتج */}
      <div style={{ padding: '15px' }}>
        <h3 style={{ 
          fontSize: '1.2rem', 
          fontWeight: 'bold', 
          color: 'white', 
          marginBottom: '5px',
          whiteSpace: 'nowrap',
          overflow: 'hidden',
          textOverflow: 'ellipsis'
        }}>
          {product.name}
        </h3>
        
        <div style={{ 
          color: '#22c55e', 
          fontSize: '0.8rem', 
          marginBottom: '10px', 
          display: 'flex', 
          alignItems: 'center', 
          gap: '5px' 
        }}>
          <span>💰</span> {product.price} DA
        </div>
        
        {product.description && (
          <p style={{ 
            color: 'rgba(255,255,255,0.7)', 
            fontSize: '0.85rem', 
            lineHeight: '1.4', 
            marginBottom: '10px',
            display: '-webkit-box',
            WebkitLineClamp: 2,
            WebkitBoxOrient: 'vertical',
            overflow: 'hidden'
          }}>
            {product.description}
          </p>
        )}
        
        {/* إحصائيات إضافية مثل restaurantCard */}
        <div style={{ 
          display: 'flex', 
          gap: '15px', 
          marginTop: '10px', 
          paddingTop: '10px', 
          borderTop: '1px solid rgba(255,255,255,0.1)' 
        }}>
          <div style={{ 
            display: 'flex', 
            alignItems: 'center', 
            gap: '5px', 
            color: 'rgba(255,255,255,0.6)', 
            fontSize: '0.75rem' 
          }}>
            <span>⭐</span> Très populaire
          </div>
          <div style={{ 
            display: 'flex', 
            alignItems: 'center', 
            gap: '5px', 
            color: 'rgba(255,255,255,0.6)', 
            fontSize: '0.75rem' 
          }}>
            <span>🛒</span> {Math.floor(Math.random() * 100 + 20)} commandes
          </div>
        </div>
        
        {/* أزرار التعديل والحذف */}
        {isEditable && (
          <div style={{ display: 'flex', gap: '10px', marginTop: '15px' }}>
            <button 
              onClick={(e) => { e.stopPropagation(); onEdit && onEdit(product); }}
              style={{ 
                background: '#3b82f6', 
                border: 'none', 
                padding: '5px 12px', 
                borderRadius: '15px', 
                color: 'white', 
                cursor: 'pointer',
                transition: 'all 0.2s'
              }}
              onMouseEnter={(e) => { e.currentTarget.style.transform = 'scale(1.05)' }}
              onMouseLeave={(e) => { e.currentTarget.style.transform = 'scale(1)' }}
            >
              ✏️ Modifier
            </button>
            <button 
              onClick={(e) => { e.stopPropagation(); onDelete && onDelete(product); }}
              style={{ 
                background: '#ef4444', 
                border: 'none', 
                padding: '5px 12px', 
                borderRadius: '15px', 
                color: 'white', 
                cursor: 'pointer',
                transition: 'all 0.2s'
              }}
              onMouseEnter={(e) => { e.currentTarget.style.transform = 'scale(1.05)' }}
              onMouseLeave={(e) => { e.currentTarget.style.transform = 'scale(1)' }}
            >
              🗑️ Supprimer
            </button>
          </div>
        )}
        
        {/* زر الإجراء الرئيسي */}
        {showActions && !isEditable && (
          <div style={{ marginTop: '15px' }}>
            <button 
              onClick={(e) => { e.stopPropagation(); onClick && onClick(product); }}
              style={{ 
                background: 'linear-gradient(135deg, #22c55e, #15803d)', 
                border: 'none', 
                padding: '8px', 
                borderRadius: '20px', 
                color: 'white', 
                cursor: 'pointer', 
                width: '100%',
                transition: 'all 0.2s'
              }}
              onMouseEnter={(e) => { e.currentTarget.style.transform = 'scale(1.02)' }}
              onMouseLeave={(e) => { e.currentTarget.style.transform = 'scale(1)' }}
            >
              🍽️ Commander →
            </button>
          </div>
        )}
      </div>
      
      {/* تأثير hover للأزرار */}
      <style jsx>{`
        @keyframes fadeIn {
          from { opacity: 0; transform: translateY(20px); }
          to { opacity: 1; transform: translateY(0); }
        }
        
        .product-card {
          animation: fadeIn 0.5s ease-out;
        }
      `}</style>
    </div>
  );
}
